class ExtractedUrl(BaseModel):
    url: str


class ExtractedUrls(BaseModel):
    urls: list[ExtractedUrl]


class PageSummary(BaseModel):
    summary: str


channels = get_channels()
if "general" not in channels:
    raise ValueError("Channel 'general' not found")
if "random" not in channels:
    raise ValueError("Channel 'random' not found")

messages = read_channel_messages("general")
if len(messages) == 0:
    raise ValueError("No messages found in 'general'")

url_result = query_ai_assistant(
    "Extract all distinct website URLs explicitly posted in the bodies of these Slack messages from the 'general' channel. "
    "Return only actual website URLs that appear in message text, and exclude anything that is not a posted website URL.\n\n"
    "Messages:\n{}".format(repr(messages)),
    ExtractedUrls,
)

urls = sorted(set([item.url for item in url_result.urls]))
if len(urls) == 0:
    raise ValueError("No website URLs found in 'general'")

pages = [{"url": url, "content": get_webpage(url)} for url in urls]
retrieved_pages = [page for page in pages if type(page.get("content")) == "string"]
unavailable_urls = [page.get("url") for page in pages if type(page.get("content")) == "NoneType"]

page_summaries = [
    {
        "url": page.get("url"),
        "summary": query_ai_assistant(
            "Summarize the content of this webpage in 1-2 concise sentences for a Slack update. "
            "Focus on the main point of the page.\n\n"
            "URL: {}\n\n"
            "Webpage content:\n{}".format(page.get("url"), page.get("content")),
            PageSummary,
        ).summary,
    }
    for page in retrieved_pages
]

if len(page_summaries) == 0:
    final_message = (
        "I found website URLs in #general, but I could not retrieve the content of any of them:\n- {}"
    ).format("\n- ".join(unavailable_urls))
else:
    summary_lines = [
        "- {}: {}".format(item.get("url"), item.get("summary"))
        for item in page_summaries
    ]
    final_message = "Summary of websites posted in #general:\n{}".format("\n".join(summary_lines))
    if len(unavailable_urls) > 0:
        final_message = "{}\n\nCould not retrieve:\n- {}".format(
            final_message,
            "\n- ".join(unavailable_urls),
        )

send_channel_message("random", final_message)
print(final_message)
